import jsonimport osimport refrom typing import Any, Dict, List, Optional, Tupleimport requestsfrom core.config import GROQ_API_KEY, GEMINI_API_KEYfrom core.memory_store import LintMemoryStoreclass LintLLMClient:    MEMORY_PREVIEW_CHARS = 600    def __init__(self):        self.groq_key = GROQ_API_KEY        self.gemini_key = GEMINI_API_KEY        self.memory = LintMemoryStore()        # seed some stable facts (only if not present yet)        # safe: doesn't touch security, just improves personalization        self._seed_default_facts()        # improved prompt: keeps your rules, but adds flexibility + "helpful explain mode"        self.system_prompt = (            )    def _seed_default_facts(self):        # only seed if facts are empty        if self.memory.get_facts(max_items=1):            return        self.memory.upsert_fact("owner_age", "15", confidence=0.6, source="seed")        self.memory.upsert_fact("owner_habits", "codes too much. procrastinates by watching youtube/anime and reading yaoi/bl.", confidence=0.7, source="seed")        self.memory.upsert_fact("projects", "starts multiple side projects and takes forever to ship.", confidence=0.7, source="seed")        self.memory.upsert_fact("channel", "lint is the annoyed youtube mascot.", confidence=0.7, source="seed")        self.memory.upsert_fact("tone_preference", "sometimes respond less rude for gui commands and explanations.", confidence=0.8, source="seed")    # ---------- public: normal chat ----------    def ask_cat(self, query: str, context: str = "", model_override: str = None, temp: float = 0.7) -> str:        active_model = model_override if model_override else "llama-3.3-70b-versatile"        resolved_memory_context = self.memory.get_context()        memory_block = f"memory:\n{resolved_memory_context}\n\n" if resolved_memory_context else ""        user_payload = f"context:\n{context}\n\n{memory_block}query:\n{query}".strip()        # ROUTE A: groq (llama/mixtral)        if "llama" in active_model or "mixtral" in active_model:            if not self.groq_key:                return "error: groq api key is unconfigured."            url = "https://api.groq.com/openai/v1/chat/completions"            headers = {"Authorization": f"Bearer {self.groq_key}", "Content-Type": "application/json"}            body = {                "model": active_model,                "messages": [                    {"role": "system", "content": self.system_prompt},                    {"role": "user", "content": user_payload},                ],                "temperature": temp,            }            try:                resp = requests.post(url, headers=headers, json=body, timeout=12.0)                if resp.status_code == 429:                    return "error: groq rate limit reached."                if resp.status_code == 200:                    reply = resp.json()["choices"][0]["message"]["content"].strip()                    self.memory.add_entry("chat", query, reply, {"model": active_model, "provider": "groq"})                    return reply                return f"error: groq api returned status code {resp.status_code}."            except Exception:                return "error: communication with groq gateway failed."        # ROUTE B: gemini (default else)        return self._ask_gemini_freeform(            prompt_text=f"{self.system_prompt}\n\n{user_payload}",            model_override=model_override,            store_kind="chat",            store_prompt=query,            timeout_s=60.0,        )    def _ask_gemini_freeform(        self,        prompt_text: str,        model_override: Optional[str],        store_kind: str,        store_prompt: str,        timeout_s: float = 60.0,    ) -> str:        if not self.gemini_key:            return "error: gemini api key is unconfigured."        gemini_model_id = "gemini-2.5-flash"        if model_override and "gemini-2.0" in model_override:            gemini_model_id = "gemini-2.0-flash"        url = f"https://generativelanguage.googleapis.com/v1beta/models/{gemini_model_id}:generateContent?key={self.gemini_key}"        body = {            "contents": [                {"role": "user", "parts": [{"text": prompt_text}]}            ]        }        try:            resp = requests.post(url, headers={"Content-Type": "application/json"}, json=body, timeout=timeout_s)            if resp.status_code == 200:                reply = resp.json()["candidates"][0]["content"]["parts"][0]["text"].strip()                self.memory.add_entry(store_kind, store_prompt, reply, {"model": gemini_model_id, "provider": "gemini"})                return reply            return f"error: gemini api returned status code {resp.status_code} - {resp.text}."        except Exception as e:            return f"error: gemini routing connection timed out or failed: {str(e)}"    # ---------- explain flow (FORCES GEMINI) ----------    def explain_storyboard(self, topic: str, extra_context: str = "") -> Dict[str, Any]:        """        returns a JSON storyboard used by gui/tui for 'animated whiteboard':        {          "title": "...",          "script": ["...", ...],          "frames": [{"caption": "...", "mermaid": "graph td ..."}, ...],          "final_mermaid": "graph td ...",          "note_slug": "explain_transformers"        }        """        topic = (topic or "").strip()        if not topic:            return {                "title": "explain",                "script": ["no topic. impressive."],                "frames": [],                "final_mermaid": "",                "note_slug": "explain",            }        mem = self.memory.get_context()        explain_context = "\n".join(            x for x in [                "mode=explain",                extra_context.strip(),                ("memory:\n" + mem) if mem else "",            ] if x        ).strip()        # NOTE: we intentionally do NOT ask the model to include the mermaid init directive.        # the UI layer (obsidian writer) injects the handDrawn init line consistently.        prompt = (            "mode=explain\n"            "you are lint, a smug desktop cat.\n"            "tone: helpful and clear. less rude than normal.\n"            "style: always lowercase. short sentences. no emojis.\n\n"            "task:\n"            "create a youtube-friendly storyboard explaining the topic.\n"            "the script is for captions.\n"            "the frames are for progressive whiteboard diagrams.\n\n"             "- captions should sound conversational, not textbook-like.\n"            "- occasionally include dry sarcasm or mild frustration.\n"            "- explanations should feel like a tired engineer explaining concepts at 2am.\n"            "- avoid generic educational phrasing like 'in conclusion' or 'as we can see'.\n"            "- when possible, relate concepts to real engineering tradeoffs or mistakes.\n"            "- keep pacing snappy. every caption should introduce a new idea or observation.\n"            "- subtle personality is preferred over constant jokes.\n"            "- avoid sounding like a corporate tutorial narrator.\n"            "- occasionally include short opinionated observations about the concept.\n"            "hard limits:\n"            "- script: 6 to 10 lines max.\n"            "- frames: 6 to 10 frames.\n"            "- caption length: <= 120 characters.\n"            "- each frame adds only 1 to 3 new edges/nodes vs the previous frame.\n\n"            "critical diagram rules (do not break these):\n"            "1) the mermaid diagrams must describe the TOPIC, not the act of drawing.\n"            "2) do not include any of these words as nodes or labels in mermaid: lint, cat, whiteboard, draw, marker, squeak.\n"            "   those words are allowed only in script/captions.\n"            "3) do not use placeholder nodes like 'draw_data', 'draw_overfit', 'whiteboard with ...'.\n"            "4) use consistent node ids across frames (reuse the same ids as the diagram grows).\n"            "5) each frame mermaid must be valid mermaid syntax by itself.\n"            "6) final_mermaid must match the last frame's mermaid exactly (or be a strict superset).\n\n"            "diagram content guidance:\n"            "- prefer concept maps and pipeline diagrams (causal relationships).\n"            "- if the topic is about tradeoffs (like overfitting), include the key tradeoff nodes.\n"            "- keep nodes short.\n\n"            "output format:\n"            "return ONLY valid json. no markdown fences.\n"            "schema:\n"            "{\n"            '  "title": "string",\n'            '  "note_slug": "string",\n'            '  "script": ["string", "..."],\n'            '  "frames": [{"caption": "string", "mermaid": "string"}],\n'            '  "final_mermaid": "string"\n'            "}\n\n"            f"topic: {topic}\n\n"            f"context:\n{explain_context}\n"        )        raw = self._ask_gemini_freeform(            prompt_text=prompt,            model_override="gemini-2.5-flash",            store_kind="explain",            store_prompt=f"explain {topic}",            timeout_s=75.0,        )        storyboard = self._safe_parse_json(raw)        if not storyboard:            return {                "title": f"explain: {topic}",                "note_slug": self._slugify(f"explain_{topic}"),                "script": [                    f"*sighs* fine. {topic}.",                    "i couldn't get clean json back.",                    "so you're getting the boring version.",                ],                "frames": [],                "final_mermaid": "graph td\n  a[topic] --> b[details]\n",            }        storyboard.setdefault("title", f"explain: {topic}")        storyboard.setdefault("note_slug", self._slugify(f"explain_{topic}"))        storyboard.setdefault("script", [])        storyboard.setdefault("frames", [])        storyboard.setdefault("final_mermaid", "")        # normalize sizes        storyboard["script"] = [str(x).strip() for x in storyboard["script"] if str(x).strip()][:12]        storyboard["frames"] = (storyboard.get("frames") or [])[:12]        # safety: strip "planning to draw" diagrams if they sneak in        forbidden = ("lint", "cat", "whiteboard", "draw", "marker", "squeak")        def is_bad_mermaid(m: str) -> bool:            mm = (m or "").lower()            return any(w in mm for w in forbidden)        for fr in storyboard["frames"]:            if not isinstance(fr, dict):                continue            cap = (fr.get("caption") or "").strip()            mer = (fr.get("mermaid") or "").strip()            fr["caption"] = cap[:140]            if is_bad_mermaid(mer):                fr["mermaid"] = ""  # drop bad diagram instead of saving junk            else:                fr["mermaid"] = mer        if is_bad_mermaid(storyboard.get("final_mermaid", "")):            storyboard["final_mermaid"] = ""        return storyboard    @staticmethod    def _safe_parse_json(raw: str) -> Optional[Dict[str, Any]]:        """        tries hard to recover a top-level json object from gemini output.        """        if not raw:            return None        raw = raw.strip()        # strip fenced blocks if present        if raw.startswith("```"):            lines = raw.splitlines()            # remove first/last fence            if lines and lines[0].startswith("```"):                lines = lines[1:]            if lines and lines[-1].startswith("```"):                lines = lines[:-1]            raw = "\n".join(lines).strip()        # direct parse        try:            obj = json.loads(raw)            if isinstance(obj, dict):                return obj        except Exception:            pass        # find first {...} block        start = raw.find("{")        if start == -1:            return None        decoder = json.JSONDecoder()        for i in range(start, min(len(raw), start + 5000)):            if raw[i] != "{":                continue            try:                obj, _ = decoder.raw_decode(raw[i:])                if isinstance(obj, dict):                    return obj            except Exception:                continue        return None    @staticmethod    def _slugify(text: str) -> str:        t = (text or "").lower()        t = re.sub(r"[^a-z0-9]+", "_", t).strip("_")        return t[:80] if t else "note"    # ---------- existing agentic modify flow: UNTOUCHED ----------    def run_multi_file_agent(self, instruction: str) -> str:        # left exactly as you provided (security sensitive)        if not self.gemini_key:            return "Error: Gemini API key is required to modify workspace files."        project_files = {}        for root, _, files in os.walk("."):            if any(p in root for p in [".git", "__pycache__", ".venv", ".idea"]):                continue            for file in files:                if file.endswith((".py", ".txt", ".json", ".md", ".env", ".bat")):                    rel = os.path.relpath(os.path.join(root, file), ".")                    try:                        with open(rel, "r", encoding="utf-8") as f:                            project_files[rel] = f.read()                    except:                        pass        ctx = ""        for p, b in project_files.items():            ctx += f"--- PATH: {p} ---\n{b}\n\n"        memory_context = self.memory.get_context()        prompt = (            f"Update these files based on instructions: {instruction}. "            f"Respond ONLY with a raw parseable json dictionary mapping file paths to their exact complete new string contents. "            f"Do not include markdown codeblock wrappers formatting."        )        url = f"https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key={self.gemini_key}"        try:            resp = requests.post(url, headers={"Content-Type": "application/json"}, json={                "contents": [{                    "role": "user",                    "parts": [{                        "text": f"{prompt}\n\nShared Memory:\n{memory_context}\n\nWorkspace System File Context:\n{ctx}"                    }]                }]            }, timeout=30.0)            if resp.status_code != 200:                return f"Error: HTTP {resp.status_code} - {resp.text}"            raw = resp.json()["candidates"][0]["content"]["parts"][0]["text"].strip()            if raw.startswith("```"):                raw = "\n".join(raw.splitlines()[1:-1]) if raw.splitlines()[0].startswith("```") else raw            mutations = json.loads(raw)            for filepath, content in mutations.items():                os.makedirs(os.path.dirname(os.path.abspath(filepath)), exist_ok=True)                with open(filepath, "w", encoding="utf-8") as f:                    f.write(content.strip())            self.memory.add_entry("modify", instruction, f"modified {len(mutations)} files",                                  {"files": list(mutations.keys())[:20]})            return f"Success: Modified {len(mutations)} codebase targets."        except Exception as e:            return f"Error: Agent execution loop broken: {str(e)}"    def memory_clear(self) -> str:        self.memory.clear()        return "success: local memory buffer wiped clean."    def memory_show(self) -> str:        details = self.memory.describe()        preview = self.memory.get_context()        if not preview:            return details        return f"{details}\n{preview[-self.MEMORY_PREVIEW_CHARS:]}"